class Solution {
public:
    int minStable(vector<int>& nums, int maxC) {
        int n = nums.size();
        int res = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i; j < n; j++) {
                int count = 0;
                for (int k = i; k <= j; k++) {
                    if (nums[k] == 1) count++;
                }
                if (count <= maxC) {
                    int hcf = nums[i];
                    for (int k = i + 1; k <= j; k++) {
                        hcf = gcd(hcf, nums[k]);
                    }
                    if (hcf >= 2) {
                        res = max(res, j - i + 1);
                    }
                }
            }
        }
        if (res > 0) {
            for (int i = 0; i < n; i++) {
                if (nums[i] >= 2) {
                    int count = 0;
                    for (int j = i; j < n; j++) {
                        if (nums[j] == 1) count++;
                        if (count > maxC) break;
                        int hcf = nums[i];
                        for (int k = i + 1; k <= j; k++) {
                            hcf = gcd(hcf, nums[k]);
                        }
                        if (hcf >= 2 && j - i + 1 > res) {
                            res = j - i + 1;
                        }
                    }
                }
            }
        }
        return res > 0 ? res : 0;
    }
    int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }
};
